import type { ScaleLinear, ScaleTime } from 'd3-scale';
import { isNumber, isUndefined } from 'lodash-es';

import type {
  ConvertibleUnit,
  FormatOptions,
  Unit,
} from '@dynatrace-sdk/units';

import type { Formatter } from '../../../../core/types/formatter.js';

/**
 * X-Axis base props
 * @public
 */
export interface BaseXAxisProps {
  /**
   * Defines x-axis label
   */
  label?: string;
  /**
   * Defines whether x-axis is showed or not
   * @defaultValue false
   */
  hidden?: boolean;
}

/**
 * X-Axis time props
 * @public
 */
export interface TimeXAxisProps {
  /**
   * Defines minimum time x-axis domain.
   * As a default, it takes the value from the data
   */
  min?: Date;
  /**
   * Defines maximum time x-axis domain.
   * As a default, it takes the value from the data
   */
  max?: Date;
}

/**
 * X-Axis timestamp props
 * @public
 */
export interface TimestampXAxisProps {
  /**
   * Defines minimum numerical x-axis domain.
   * As a default, it takes the value from the data
   */
  min?: Date | number;
  /**
   * Defines maximum numerical x-axis domain.
   * As a default, it takes the value from the data
   */
  max?: Date | number;
  /**
   * If the value is set to time, it enables data casting from timestamps to Date objects
   */
  type: 'time';
}

/**
 * X-Axis numerical props
 * @public
 */
export interface NumericalXAxisProps {
  /**
   * Defines minimum numerical x-axis domain.
   * As a default, it takes the value from the data
   */
  min?: number;
  /**
   * Defines maximum numerical x-axis domain.
   * As a default, it takes the value from the data
   */
  max?: number;
  /**
   * Defines x-axis scale type. If the value is set to time, it enables data casting from timestamps to Date objects
   * @defaultValue 'linear'
   */
  type?: 'linear' | 'log';
  /**
   * Defines x-axis tick formatting
   */
  formatter?: Formatter | FormatOptions<Unit, ConvertibleUnit>;
  /**
   * Defines x-axis unit
   */
  unit?: string;
}

/**
 * The props for X-Axis component in the annotations
 * @public
 */
export type XAxisProps = BaseXAxisProps &
  (TimeXAxisProps | TimestampXAxisProps | NumericalXAxisProps);

/** @internal */
export type XAxisConfig = XAxisProps & {
  /** Make hidden required internally */
  hidden: boolean;
};

/**
 * The props for X-Axis component configuration
 * @public
 */
export type XAxisConfigProps = XAxisProps & {
  min?: Date | number | string;
  max?: Date | number | string;
};

/**
 * @internal
 */
export const isNumericalAxis = (
  props: XAxisProps,
): props is NumericalXAxisProps => {
  if ('type' in props) {
    return props.type !== 'time';
  }

  if (!isUndefined(props.min)) {
    return isNumber(props.min);
  }

  if (!isUndefined(props.max)) {
    return isNumber(props.max);
  }

  return 'formatter' in props || 'unit' in props;
};

/**
 * @internal
 */
export const isTimestampAxis = (
  props: XAxisProps,
): props is TimestampXAxisProps => {
  return 'type' in props && props.type === 'time';
};

/**
 * @internal
 */
export const isNumericalScale = (
  scale: ScaleTime<number, number> | ScaleLinear<number, number>,
): scale is ScaleLinear<number, number> => {
  return typeof scale.invert(0) === 'number';
};
